using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.ShortRun.WithId("net9.0").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core90))
    .AddJob(Job.ShortRun.WithId("net10.0").WithRuntime(BenchmarkDotNet.Environments.CoreRuntime.Core100));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _smallAnalyzer = null!;
    private TextAnalyzer _largeAnalyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        var small = "The quick brown fox jumps over the lazy dog near the river bank";
        var large = string.Join(' ', Enumerable.Range(0, 10_000).Select(i => $"word{i % 500}"));
        _smallAnalyzer = new TextAnalyzer(small);
        _largeAnalyzer = new TextAnalyzer(large);
    }

    [Benchmark] public double AverageWordLength_Small() => _smallAnalyzer.AverageWordLength();
    [Benchmark] public double AverageWordLength_Large() => _largeAnalyzer.AverageWordLength();
    [Benchmark] public object WordLengthHistogram_Small() => _smallAnalyzer.WordLengthHistogram();
    [Benchmark] public object WordLengthHistogram_Large() => _largeAnalyzer.WordLengthHistogram();
    [Benchmark] public int UniqueWordCount_Small() => _smallAnalyzer.UniqueWordCount();
    [Benchmark] public int UniqueWordCount_Large() => _largeAnalyzer.UniqueWordCount();
}

